AM,OAAO,6BAA6B;IAGxC,KAAK,CAAC,QAAQ,CAAC,MAAuB;QACpC,MAAM,EAAE,GAAG,EAAE,GAAG,MAAM,CAAC;QACvB,IAAI,CAAC;YACH,IAAI,aAAa,CAAC,GAAG,CAAC,CAAC,MAAM,IAAI,CAAC,EAAE,CAAC;gBACnC,OAAO,EAAE,EAAE,EAAE,IAAI,EAAE,CAAC;YACtB,CAAC;iBAAM,CAAC;gBACN,OAAO;oBACL,EAAE,EAAE,KAAK;oBACT,KAAK,EAAE,IAAI,wBAAwB,EAAE;iBACtC,CAAC;YACJ,CAAC;QACH,CAAC;QAAC,OAAO,GAAG,EAAE,CAAC;YACb,OAAO;gBACL,EAAE,EAAE,KAAK;gBACT,KAAK,EAAE,GAAG;aACX,CAAC;QACJ,CAAC;IACH,CAAC;CACF;AAED,MAAM,CAAC,MAAM,6BAA6B,GAAG,IAAI,kBAAkB,CAIhE,IAAI,qBAAqB,EAAE,EAAE,IAAI,+BAA+B,EAAE,CAAC,CAAC;AAEvE,MAAM,CAAC,MAAM,2BAA2B,GAAG,IAAI,kBAAkB,CAE9D,IAAI,qBAAqB,EAAE,EAAE,IAAI,6BAA6B,EAAE,CAAC,CAAC","sourcesContent":["import { existsSync, readdirSync } from "node:fs";
import path from "node:path";
import { simpleGit } from "simple-git";
import { findTestFiles } from "../../test/test-files.js";
import { CompositeValidator, Result, ValidationRule } from "./lib.js";

export class GitBranchOrEnvironmentRequiredError extends Error {
  constructor() {
    super(
      "Invalid arguments: The project directory is not a Git repository, you must specify the `environment` argument or set `--use-git-branch false` to pick one."
    );
    Object.setPrototypeOf(this, NotAGitRepoError.prototype);
  }
}

export class NotAGitRepoError extends Error {
  constructor() {
    super("Invalid directory: The project directory is not a Git repository.");
    Object.setPrototypeOf(this, NotAGitRepoError.prototype);
  }
}

export class NotAZuploProject extends Error {
  constructor() {
    super(
      "Invalid directory: The project directory is not the root of a Zuplo project."
    );
    Object.setPrototypeOf(this, NotAZuploProject.prototype);
  }
}

export class ZuploProjectMissingTests extends Error {
  constructor() {
    super(
      "Invalid directory: The project directory does not contain any tests (*.test.ts) in the /tests folder. Create a at least one test of the form some-name.test.ts"
    );
    Object.setPrototypeOf(this, ZuploProjectMissingTests.prototype);
  }
}

export class NoGitCommits extends Error {
  constructor() {
    super(
      "Invalid Git state: The project directory does not contain any commits. Make a commit before deploying."
    );
    Object.setPrototypeOf(this, NoGitCommits.prototype);
  }
}

export class NotOnAGitBranch extends Error {
  constructor() {
    super(
      "Invalid Git state: You are not on a branch. Run `git checkout -b <branch-name>` to create a new branch."
    );
    Object.setPrototypeOf(this, NotOnAGitBranch.prototype);
  }
}

export class GitVersionControlValidator
  implements ValidationRule<{ dir: string }>
{
  async validate(option: { dir: string }): Promise<Result> {
    const { dir } = option;
    try {
      await simpleGit({ baseDir: dir }).status();
      return { ok: true };
    } catch (_err) {
      return {
        ok: false,
        error: new NotAGitRepoError(),
      };
    }
  }
}

/**
 * Checks if either the current branch is set as the environment or if
 * the environment is explicitly set
 */
export class GitBranchOrEnvironmentValidator
  implements ValidationRule<{ dir: string }>
{
  async validate(option: {
    dir: string;
    environment: string | undefined;
  }): Promise<Result> {
    const { dir, environment } = option;
    if (typeof environment === "string") {
      return {
        ok: true,
      };
    }
    try {
      if (await simpleGit({ baseDir: dir }).checkIsRepo()) {
        await simpleGit({ baseDir: dir }).status();
        const git = simpleGit({ baseDir: dir });
        const branch = await git.branch();
        if (branch.current) {
          return {
            ok: true,
          };
        }
      }
    } catch {
      // Ignore
    }
    return {
      ok: false,
      error: new GitBranchOrEnvironmentRequiredError(),
    };
  }
}

export class GitCommitValidator implements ValidationRule<{ dir: string }> {
  async validate(option: { dir: string }): Promise<Result> {
    const { dir } = option;
    try {
      const git = simpleGit({ baseDir: dir });
      const commits = await git.log({ maxCount: 1 });
      if (commits.total === 0) {
        return {
          ok: false,
          error: new NoGitCommits(),
        };
      }
      return { ok: true };
    } catch (_err) {
      return {
        ok: false,
        error: new NoGitCommits(),
      };
    }
  }
}

export class GitBranchValidator implements ValidationRule<{ dir: string }> {
  async validate(option: { dir: string }): Promise<Result> {
    const { dir } = option;
    const git = simpleGit({ baseDir: dir });
    const branch = await git.branch();
    if (!branch.current) {
      return {
        ok: false,
        error: new NotOnAGitBranch(),
      };
    }

    return { ok: true };
  }
}

export class ZuploProjectValidator implements ValidationRule<{ dir: string }> {
  async validate(options: { dir: string }): Promise<Result> {
    const { dir } = options;
    try {
      const dirPath = path.join(path.normalize(dir), "config");
      if (existsSync(dirPath)) {
        const files = readdirSync(dirPath);
        const existingOASFiles =
          files.filter((file) => file.endsWith(".oas.json")).length >= 1;
        if (existingOASFiles === true) {
          return { ok: true };
        }
      }
      return {
        ok: false,
        error: new NotAZuploProject(),
      };
    } catch (err) {
      return {
        ok: false,
        error: err,
      };
    }
  }
}

export class ZuploProjectHasTestsValidator
  implements ValidationRule<{ dir: string }>
{
  async validate(option: { dir: string }): Promise<Result> {
    const { dir } = option;
    try {
      if (findTestFiles(dir).length >= 1) {
        return { ok: true };
      } else {
        return {
          ok: false,
          error: new ZuploProjectMissingTests(),
        };
      }
    } catch (err) {
      return {
        ok: false,
        error: err,
      };
    }
  }
}

export const validDeployDirectoryValidator = new CompositeValidator<{
  dir: string;
  project: string | undefined;
  environment: string | undefined;
}>(new ZuploProjectValidator(), new GitBranchOrEnvironmentValidator());

export const validTestDirectoryValidator = new CompositeValidator<{
  dir: string;
}>(new ZuploProjectValidator(), new ZuploProjectHasTestsValidator());
"]}
